1	// SPDX-FileCopyrightText: Copyright (c) 2025-2026 NVIDIA CORPORATION & AFFILIATES. All rights reserved.
2	// SPDX-License-Identifier: Apache-2.0
3	
4	//! Persistence layer for `OpenShell` Server.
5	
6	mod postgres;
7	mod sqlite;
8	
9	use openshell_core::{Error, Result};
10	use prost::Message;
11	use rand::Rng;
12	use std::time::{SystemTime, UNIX_EPOCH};
13	
14	pub use postgres::PostgresStore;
15	pub use sqlite::SqliteStore;
16	
17	/// Stored object record.
18	#[derive(Debug, Clone)]
19	pub struct ObjectRecord {
20	    pub object_type: String,
21	    pub id: String,
22	    pub name: String,
23	    pub payload: Vec<u8>,
24	    pub created_at_ms: i64,
25	    pub updated_at_ms: i64,
26	}
27	
28	/// Stored sandbox policy revision record.
29	#[derive(Debug, Clone)]
30	pub struct PolicyRecord {
31	    pub id: String,
32	    pub sandbox_id: String,
33	    pub version: i64,
34	    pub policy_payload: Vec<u8>,
35	    pub policy_hash: String,
36	    pub status: String,
37	    pub load_error: Option<String>,
38	    pub created_at_ms: i64,
39	    pub loaded_at_ms: Option<i64>,
40	}
41	
42	/// Persistence store implementations.
43	#[derive(Debug, Clone)]
44	pub enum Store {
45	    Postgres(PostgresStore),
46	    Sqlite(SqliteStore),
47	}
48	
49	/// Trait for inferring an object type string from a message type.
50	pub trait ObjectType {
51	    fn object_type() -> &'static str;
52	}
53	
54	/// Trait for extracting an object id from a message instance.
55	pub trait ObjectId {
56	    fn object_id(&self) -> &str;
57	}
58	
59	/// Trait for extracting an object name from a message instance.
60	pub trait ObjectName {
61	    fn object_name(&self) -> &str;
62	}
63	
64	/// Generate a random 6-character lowercase alphabetic name.
65	pub fn generate_name() -> String {
66	    let mut rng = rand::rng();
67	    (0..6)
68	        .map(|_| rng.random_range(b'a'..=b'z') as char)
69	        .collect()
70	}
71	
72	impl Store {
73	    /// Connect to a persistence store based on the database URL.
74	    pub async fn connect(url: &str) -> Result<Self> {
75	        if url.starts_with("postgres://") || url.starts_with("postgresql://") {
76	            let store = PostgresStore::connect(url).await?;
77	            store.migrate().await?;
78	            Ok(Self::Postgres(store))
79	        } else if url.starts_with("sqlite:") {
80	            let store = SqliteStore::connect(url).await?;
81	            store.migrate().await?;
82	            Ok(Self::Sqlite(store))
83	        } else {
84	            Err(Error::config(format!(
85	                "unsupported database URL scheme: {url}"
86	            )))
87	        }
88	    }
