3884	/// Check whether an IP address is safe to use as an SSH proxy target.
3885	///
3886	/// Blocks loopback (prevents connecting back to the gateway server itself)
3887	/// and link-local addresses (prevents cloud metadata SSRF via 169.254.169.254).
3888	fn is_safe_ssh_proxy_target(ip: std::net::IpAddr) -> bool {
3889	    match ip {
3890	        std::net::IpAddr::V4(v4) => {
3891	            !v4.is_loopback() // 127.0.0.0/8
3892	            && !v4.is_link_local() // 169.254.0.0/16 (cloud metadata)
3893	        }
3894	        std::net::IpAddr::V6(v6) => {
3895	            if v6.is_loopback() {
3896	                return false; // ::1
3897	            }
3898	            // Check IPv4-mapped IPv6 addresses like ::ffff:127.0.0.1
3899	            if let Some(v4) = v6.to_ipv4_mapped() {
3900	                return !v4.is_loopback() && !v4.is_link_local();
3901	            }
3902	            true
3903	        }
3904	    }
3905	}
