3907	async fn start_single_use_ssh_proxy(
3908	    target_host: &str,
3909	    target_port: u16,
3910	    handshake_secret: &str,
3911	) -> Result<(u16, tokio::task::JoinHandle<()>), Box<dyn std::error::Error + Send + Sync>> {
3912	    let listener = TcpListener::bind(("127.0.0.1", 0)).await?;
3913	    let port = listener.local_addr()?.port();
3914	    let target_host = target_host.to_string();
3915	    let handshake_secret = handshake_secret.to_string();
3916	
3917	    let task = tokio::spawn(async move {
3918	        let Ok((mut client_conn, _)) = listener.accept().await else {
3919	            warn!("SSH proxy: failed to accept local connection");
3920	            return;
3921	        };
3922	
3923	        // Resolve DNS and validate the target IP before connecting.
3924	        // This prevents SSRF if the sandbox status record were poisoned
3925	        // to point at loopback, cloud metadata, or other internal services.
3926	        let addr_str = format!("{}:{}", target_host, target_port);
3927	        let resolved = match tokio::net::lookup_host(&addr_str).await {
3928	            Ok(mut addrs) => match addrs.next() {
3929	                Some(addr) => addr,
3930	                None => {
3931	                    warn!(target_host = %target_host, "SSH proxy: DNS resolution returned no addresses");
3932	                    return;
3933	                }
3934	            },
3935	            Err(e) => {
3936	                warn!(target_host = %target_host, error = %e, "SSH proxy: DNS resolution failed");
3937	                return;
3938	            }
3939	        };
3940	
3941	        if !is_safe_ssh_proxy_target(resolved.ip()) {
3942	            warn!(
3943	                target_host = %target_host,
3944	                resolved_ip = %resolved.ip(),
3945	                "SSH proxy: target resolved to blocked IP range (loopback or link-local)"
3946	            );
3947	            return;
3948	        }
3949	
3950	        debug!(
3951	            target_host = %target_host,
3952	            resolved_ip = %resolved.ip(),
3953	            target_port,
3954	            "SSH proxy: connecting to validated target"
3955	        );
3956	
3957	        // Connect to the resolved address directly (not the hostname) to
3958	        // prevent TOCTOU between validation and connection.
3959	        let Ok(mut sandbox_conn) = TcpStream::connect(resolved).await else {
3960	            warn!(target_host = %target_host, resolved_ip = %resolved.ip(), target_port, "SSH proxy: failed to connect to sandbox");
3961	            return;
3962	        };
3963	        let Ok(preface) = build_preface(&uuid::Uuid::new_v4().to_string(), &handshake_secret)
3964	        else {
3965	            warn!("SSH proxy: failed to build handshake preface");
3966	            return;
3967	        };
3968	        if let Err(e) = sandbox_conn.write_all(preface.as_bytes()).await {
3969	            warn!(error = %e, "SSH proxy: failed to send handshake preface");
3970	            return;
3971	        }
3972	        let mut response = String::new();
3973	        if let Err(e) = read_line(&mut sandbox_conn, &mut response).await {
3974	            warn!(error = %e, "SSH proxy: failed to read handshake response");
3975	            return;
3976	        }
3977	        if response.trim() != "OK" {
3978	            warn!(response = %response.trim(), "SSH proxy: handshake rejected by sandbox");
3979	            return;
3980	        }
3981	        let _ = tokio::io::copy_bidirectional(&mut client_conn, &mut sandbox_conn).await;
3982	    });
3983	
3984	    Ok((port, task))
3985	}
