3987	fn build_preface(
3988	    token: &str,
3989	    secret: &str,
3990	) -> Result<String, Box<dyn std::error::Error + Send + Sync>> {
3991	    let timestamp = i64::try_from(
3992	        std::time::SystemTime::now()
3993	            .duration_since(std::time::UNIX_EPOCH)
3994	            .map_err(|_| "time error")?
3995	            .as_secs(),
3996	    )
3997	    .map_err(|_| "time error")?;
3998	    let nonce = uuid::Uuid::new_v4().to_string();
3999	    let payload = format!("{token}|{timestamp}|{nonce}");
4000	    let signature = hmac_sha256(secret.as_bytes(), payload.as_bytes());
4001	    Ok(format!("NSSH1 {token} {timestamp} {nonce} {signature}\n"))
4002	}
