4004	async fn read_line(
4005	    stream: &mut TcpStream,
4006	    buf: &mut String,
4007	) -> Result<(), Box<dyn std::error::Error + Send + Sync>> {
4008	    let mut bytes = Vec::new();
4009	    loop {
4010	        let mut byte = [0_u8; 1];
4011	        let n = stream.read(&mut byte).await?;
4012	        if n == 0 {
4013	            break;
4014	        }
4015	        if byte[0] == b'\n' {
4016	            break;
4017	        }
4018	        bytes.push(byte[0]);
4019	        if bytes.len() > 1024 {
4020	            break;
4021	        }
4022	    }
4023	    *buf = String::from_utf8_lossy(&bytes).to_string();
4024	    Ok(())
4025	}
