4126	/// Merge an incoming map into an existing map.
4127	///
4128	/// - If `incoming` is empty, return `existing` unchanged (no-op).
4129	/// - Otherwise, upsert all incoming entries into `existing`.
4130	/// - Entries with an empty-string value are removed (delete semantics).
4131	fn merge_map(
4132	    mut existing: std::collections::HashMap<String, String>,
4133	    incoming: std::collections::HashMap<String, String>,
4134	) -> std::collections::HashMap<String, String> {
4135	    if incoming.is_empty() {
4136	        return existing;
4137	    }
4138	    for (key, value) in incoming {
4139	        if value.is_empty() {
4140	            existing.remove(&key);
4141	        } else {
4142	            existing.insert(key, value);
4143	        }
4144	    }
4145	    existing
4146	}
