4148	async fn update_provider_record(
4149	    store: &crate::persistence::Store,
4150	    provider: Provider,
4151	) -> Result<Provider, Status> {
4152	    if provider.name.is_empty() {
4153	        return Err(Status::invalid_argument("provider.name is required"));
4154	    }
4155	
4156	    let existing = store
4157	        .get_message_by_name::<Provider>(&provider.name)
4158	        .await
4159	        .map_err(|e| Status::internal(format!("fetch provider failed: {e}")))?;
4160	
4161	    let Some(existing) = existing else {
4162	        return Err(Status::not_found("provider not found"));
4163	    };
4164	
4165	    // Provider type is immutable after creation. Reject if the caller
4166	    // sends a non-empty type that differs from the existing one.
4167	    let incoming_type = provider.r#type.trim();
4168	    if !incoming_type.is_empty() && !incoming_type.eq_ignore_ascii_case(existing.r#type.trim()) {
4169	        return Err(Status::invalid_argument(
4170	            "provider type cannot be changed; delete and recreate the provider",
4171	        ));
4172	    }
4173	
4174	    let updated = Provider {
4175	        id: existing.id,
4176	        name: existing.name,
