    #[test]
    fn ssh_proxy_target_allows_pod_network_ips() {
        use std::net::{IpAddr, Ipv4Addr};
        // Typical pod network IPs should be allowed
        assert!(is_safe_ssh_proxy_target(IpAddr::V4(Ipv4Addr::new(
            10, 0, 0, 5
        ))));
        assert!(is_safe_ssh_proxy_target(IpAddr::V4(Ipv4Addr::new(
