#[tokio::test]
async fn sandbox_duplicate_name_returns_already_exists() {
    let store = Store::connect("sqlite::memory:?cache=shared")
        .await
        .unwrap();

    let first = Sandbox {
        id: "sandbox-id-1".to_string(),
        name: "dupe-test".to_string(),
        namespace: "default".to_string(),
        spec: Some(SandboxSpec::default()),
        phase: SandboxPhase::Provisioning as i32,
        ..Default::default()
    };
    persist_new_sandbox_record(&store, &first).await.unwrap();

    let duplicate = Sandbox {
        id: "sandbox-id-2".to_string(),
        name: "dupe-test".to_string(),
        namespace: "default".to_string(),
        spec: Some(SandboxSpec::default()),
        phase: SandboxPhase::Provisioning as i32,
        ..Default::default()
    };
    let err = persist_new_sandbox_record(&store, &duplicate)
        .await
        .unwrap_err();

    assert_eq!(err.code(), Code::AlreadyExists);
    assert!(err.message().contains("sandbox 'dupe-test' already exists"));
    assert!(err.message().contains("openshell sandbox delete dupe-test"));
    assert!(!err.message().contains("UNIQUE constraint"));
    assert!(!err.message().contains("database error"));
}

