    // ---- conflict guard: global overrides block sandbox mutations ----

    #[tokio::test]
    async fn conflict_guard_sandbox_set_blocked_when_global_exists() {
        let store = Store::connect("sqlite::memory:?cache=shared")
            .await
            .unwrap();

