+async fn persist_new_sandbox_record(
+    store: &crate::persistence::Store,
+    sandbox: &Sandbox,
+) -> Result<(), Status> {
+    let existing = store
+        .get_message_by_name::<Sandbox>(&sandbox.name)
+        .await
+        .map_err(|e| Status::internal(format!("fetch sandbox failed: {e}")))?;
+
+    if existing.is_some() {
+        return Err(Status::already_exists(format!(
+            "sandbox '{}' already exists\n\nhint: delete it first with: openshell sandbox delete {}\n      or use a different name",
+            sandbox.name, sandbox.name
+        )));
+    }
+
+    store
+        .put_message(sandbox)
+        .await
+        .map_err(|e| Status::internal(format!("persist sandbox failed: {e}")))
+}
